+import { NormalizedErrorStackOptions } from './error-options.js';
+
+export function normalizeStackNewlines(stack: string): string {
+  return stack.replace(/\\r\
?/g, '\
');
+}
+
+function redactPaths(line: string, mode: NormalizedErrorStackOptions['redactPaths']): string {
+  if (mode === 'strip_cwd') {
+    const cwd = typeof process !== 'undefined' ? process.cwd().replace(/\\\\/g, '/') : '';
+    return cwd ? line.replaceAll(cwd, '') : line;
+  }
+  if (mode === 'basename') {
+    return line.replace(/((?:[A-Za-z]:)?[^\\s()]*[\\\\/])([^\\\\/\\s()]+)/g, '$2');
+  }
+  return line;
+}
+
+function isInternalFrame(line: string, mode: NormalizedErrorStackOptions['stripInternalFrames']): boolean {
+  const node = mode === 'node' || mode === 'node_and_superjson';
+  const superjson = mode === 'superjson' || mode === 'node_and_superjson';
+  return (node && line.includes('node:internal')) ||
+    (superjson && /src\\/(transformer|plainer|index)\\.ts/.test(line));
+}
+
+function processLines(stack: string, options: NormalizedErrorStackOptions, frames: boolean): string[] {
+  let lines = (options.normalizeNewlines ? normalizeStackNewlines(stack) : stack).split(/\\r?\
/);
+  lines = lines.map((line, index) =>
+    index > 0 && options.trimLeadingWhitespace ? line.trimStart() : line
+  );
+  if (frames) {
+    lines = lines.filter((line, index) => index === 0 || !isInternalFrame(line, options.stripInternalFrames));
+    lines = lines.map(line => redactPaths(line, options.redactPaths));
+  } else {
+    lines = lines.map(line => redactPaths(line, options.redactPaths));
+    if (options.maxStackLines !== undefined) lines = lines.slice(0, options.maxStackLines);
+    lines = lines.filter((line, index) => index === 0 || !isInternalFrame(line, options.stripInternalFrames));
+  }
+  if (frames && options.maxStackLines !== undefined) lines = lines.slice(0, options.maxStackLines);
+  return lines;
+}
+
+export function processStackString(stack: string, options: NormalizedErrorStackOptions): string {
+  return processLines(stack, options, false).join('\
');
+}
+
+export function processStackFrames(stack: string, options: NormalizedErrorStackOptions): { raw: string }[] {
+  return processLines(stack, options, true).map(raw => ({ raw }));
+}
