+function usesErrorStack(error: Error, superJson: SuperJSON): boolean {
+  const options = superJson.errorStackOptions;
+  return !!options && options.mode !== 'off' && matchesErrorClass(error, superJson);
+}
+
+function makeError(error: Error, value: any): Error {
+  const hasAggregateErrors = Array.isArray(value.errors);
+  const AggregateErrorConstructor = (globalThis as any).AggregateError;
+  const result: Error = hasAggregateErrors && AggregateErrorConstructor
+    ? new AggregateErrorConstructor(value.errors, value.message, { cause: value.cause })
+    : new Error(value.message, { cause: value.cause });
+  result.name = value.name;
+  if (typeof value.stack === 'string') result.stack = value.stack;
