+function serializeConfiguredCause(
+  error: Error,
+  superJson: SuperJSON,
+  depth: number,
+  seen: Set<Error>
+): any {
+  if (seen.has(error)) return undefined;
+  seen.add(error);
+  const options = superJson.errorStackOptions!;
+  const applies = matchesErrorClass(error, superJson);
+  const value: any = {
+    name: error.name,
+    message: applies && options.sanitizeMessage
+      ? sanitizeMessage(error.message)
+      : error.message,
+  };
+  if (applies && options.mode === 'string' && superJson.allowedErrorProps.includes('stack') && typeof error.stack === 'string') {
+    value.stack = processStackString(error.stack, options);
+  }
+  if (applies && options.mode === 'frames' && superJson.allowedErrorProps.includes('stackFrames') && typeof error.stack === 'string') {
+    value.stackFrames = processStackFrames(error.stack, options);
+  }
+  if (Array.isArray((error as any).errors)) value.errors = (error as any).errors;
+  if (
+    options.includeCauses !== 'none' &&
+    error.cause instanceof Error &&
+    (options.includeCauses === 'direct' ? depth === 0 : depth < options.maxCauseDepth)
+  ) {
+    const cause = serializeConfiguredCause(error.cause, superJson, depth + 1, seen);
+    if (cause !== undefined) value.cause = cause;
+  }
+  const processor = superJson.errorClassRegistry.getProcessor(error.name);
+  return processor ? processor(value) : value;
+}
+
+function restoreConfiguredCause(value: any): any {
+  if (!value || typeof value !== 'object' || typeof value.name !== 'string' || typeof value.message !== 'string') {
+    return value;
+  }
+  const cause = restoreConfiguredCause(value.cause);
+  const restored = makeError(new Error(value.message), { ...value, cause });
+  if (Array.isArray(value.errors)) (restored as any).errors = value.errors;
+  return restored;
+}
